const fs = global.get('fs') || require('fs');
const path = (process.env.NODE_RED_USER_DIR || '/data') + '/clusterra-creds.json';
const c = JSON.parse(fs.readFileSync(path, 'utf8'));
msg.headers = { 'Authorization': 'Bearer ' + c.auth_token, 'Content-Type': 'application/json' };
msg.url = c.api_url + '/v1/clusters/' + c.cluster_id + '/jobs/submit';
msg.payload = {
    template_id: 'custom-slurm',
    params: {
        job_name: 'nodered-hello',
        script_body: '#!/bin/bash\necho hello from node-red\nsleep 30',
        cpus: 1
    }
};
flow.set('cluster_id', c.cluster_id);
flow.set('api_url', c.api_url);
flow.set('auth', msg.headers.Authorization);
return msg;

msg.url = flow.get('api_url') + '/v1/clusters/' + flow.get('cluster_id') + '/jobs/' + msg.payload.job_id;
msg.method = 'GET';
msg.headers = { 'Authorization': flow.get('auth') };
return msg;
